DROP TABLE IF EXISTS `conferences`;


CREATE TABLE `conferences` (
  `id` int NOT NULL AUTO_INCREMENT,
  `acronym` varchar(50) COLLATE utf8mb4_general_ci NOT NULL,
  `name` varchar(255) COLLATE utf8mb4_general_ci NOT NULL,
  `email` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `logo_url` varchar(2083) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `banner_url` varchar(2083) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `email_text` text COLLATE utf8mb4_general_ci,
  `email_subject` varchar(255) COLLATE utf8mb4_general_ci DEFAULT 'Your Event Access QR Code',
  `how_to_get_there_url` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `voting_window_open` tinyint(1) DEFAULT '0',
  `door_sign_bg` text COLLATE utf8mb4_general_ci,
  `door_sign_config` json DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `acronym` (`acronym`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;



LOCK TABLES `conferences` WRITE;

INSERT INTO `conferences` VALUES (1,'HOPV25','Hybrid and Organic Photovoltaics',NULL,'','https://www.nanoge.org/static/events/4d2d04a17c3fb1eedf2d712a12ff5c9dfac84046','Here is your QR code for accessing the event.','Your Event Access QR Code',NULL,'2026-03-04 14:31:21',0,NULL,NULL),(2,'MATSUS26','Materials for Sustainable Development Conference',NULL,'','https://www.nanoge.org/static/events/905509be52e5f69b535a058c85f201e961a141b5','Here is your QR code for the Conference Social Dinner.\r\nThe dinner will take place at Xalet de Montjuïc, on Wednesday, March 25th at 20:00h.\r\nPlease arrive at least 15 minutes in advance.','MatsusSpring26 - Social Dinner QR Code','https://maps.app.goo.gl/SaGsn5kvxX8g9kih8','2026-03-04 14:55:06',0,NULL,NULL),(3,'prueba01','prueba 2026','','','https://www.nanoge.org/static/events/905509be52e5f69b535a058c85f201e961a141b5','Here is your QR code for accessing the event.','Your Event Access QR Code',NULL,'2026-03-24 15:25:46',0,NULL,NULL),(4,'H2Future26','The Future of Hydrogen: Science, Applications and Energy Transition',NULL,'https://www.nanoge.org/static/events/b389a588d02be72a296f8b8a9d9fdf50dc66058c','https://www.nanoge.org/static/events/65d49b9cf238750c7ecd2df6b10e47259e19afdc','Here is your QR code for accessing the event.','Your Event Access QR Code','','2026-04-21 09:04:36',0,NULL,NULL),(5,'HOPV26','HOPV 2026','hopv26@nanoge.org',NULL,NULL,NULL,'Your Event Access QR Code',NULL,'2026-04-28 09:37:34',1,NULL,NULL);

