DROP TABLE IF EXISTS `nfc_tags`;


CREATE TABLE `nfc_tags` (
  `id` int NOT NULL AUTO_INCREMENT,
  `tag_id` varchar(255) NOT NULL,
  `used` tinyint(1) DEFAULT '0',
  `used_at` datetime DEFAULT NULL,
  `user` varchar(255) DEFAULT NULL,
  `email` varchar(255) DEFAULT NULL,
  `ticket` varchar(255) DEFAULT NULL,
  `conference_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `tag_id` (`tag_id`),
  KEY `fk_conference` (`conference_id`),
  CONSTRAINT `fk_conference` FOREIGN KEY (`conference_id`) REFERENCES `conferences` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=1779 DEFAULT CHARSET=utf8mb4;



