DROP TABLE IF EXISTS `payments`;


CREATE TABLE `payments` (
  `id` int NOT NULL AUTO_INCREMENT,
  `registration_id` int NOT NULL,
  `amount` decimal(10,2) DEFAULT NULL,
  `currency` varchar(10) DEFAULT 'EUR',
  `status` varchar(50) DEFAULT NULL,
  `payment_method` varchar(50) DEFAULT NULL,
  `mongo_id` varchar(100) DEFAULT NULL,
  `tickets_info` json DEFAULT NULL,
  `group_name` varchar(100) DEFAULT NULL,
  `client_country_id` varchar(100) DEFAULT NULL,
  `client_name` varchar(255) DEFAULT NULL,
  `invoice_code` varchar(100) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `mongo_id` (`mongo_id`),
  KEY `fk_registration` (`registration_id`),
  CONSTRAINT `fk_registration` FOREIGN KEY (`registration_id`) REFERENCES `registrations` (`id`) ON DELETE CASCADE
