UNLOCK TABLES;


DROP TABLE IF EXISTS `posters`;


CREATE TABLE `posters` (
  `id` int NOT NULL AUTO_INCREMENT,
  `conference_id` int DEFAULT NULL,
  `mongo_id` varchar(255) DEFAULT NULL,
  `title` varchar(1000) DEFAULT NULL,
  `authors` text,
  `content` longtext,
  `points` int DEFAULT '0',
  `votes_received` json DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `code` varchar(50) DEFAULT NULL,
  `cluster_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `conference_id` (`conference_id`),
  KEY `fk_poster_cluster` (`cluster_id`),
  CONSTRAINT `fk_poster_cluster` FOREIGN KEY (`cluster_id`) REFERENCES `clusters` (`id`) ON DELETE SET NULL,
  CONSTRAINT `posters_ibfk_1` FOREIGN KEY (`conference_id`) REFERENCES `conferences` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=82 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



